#include<bits/stdc++.h>
using namespace std;
struct node
{
	int val;
	node *pre,*nxt;
};
class List
{
	private:
		int cnt;
		node *head1,*end1;
	public:
		typedef node* iterator;
		iterator head()
		//node* head()
		{
			return head1;
		}
		iterator end()
		{
			return end1;
		}
		List():head1(NULL),end1(NULL),cnt(0){}
		void push_back(int num)
		{
			node *now=new node;
			now->val=num;
			now->nxt=NULL;
			cnt++;
			if(head1==NULL)
			{
				head1=now;
				now->pre=NULL;
				end1=now;
				return;
			}
			end1->nxt=now;
			now->pre=end1;
			end1=now;
			return;
		}
		int size()
		{
			return cnt;
		}
		bool remove(iterator x)
		{
			if(x==NULL)
			{
				return false;
			}
			if(x==head1)
			{
				head1=x->nxt;
			}
			else
			{
				x->pre->nxt=x->nxt;
			}
			if(x==end1)
		
			{
				end1=x->pre;
				
			}
			else
			{
				x->nxt->pre=x->pre;
			
			}
			delete x;
			cnt--;
			return true;
		}
		iterator sit(const int x)
		{
			if(x<=0||x>cnt)
			{
				return NULL;
			}
			int i=1;
			for(node* a=head1;a!=NULL;a=a->nxt,i++)
			{
				if(i==x)
				{
					return a;
				}
			}
			return NULL;
		}
		bool empty()
		{
			return cnt==0;
		}
};
int a[10001];
bool f()
{
	List l;
	int n,m,k;
	scanf("%d%d%d",&m,&n,&k);
	memset(a,0,sizeof(a));
	for(int i=1;i<=n;i++)
	{
		int temp;
		scanf("%d",&temp);
		a[temp]++;
		l.push_back(temp);
	}
	node*t=l.head();
	int l_top=1,r_top=1;
	//while(l_top<=m&&!l.empty())
	while(l_top<=m&&l.size()>0)
	{
		while(l_top<=m&&a[l_top]==0)
		{
			l_top++;
		}
		while(l.size()>0&&l.size()-r_top+1<k&&r_top!=1)
		{
			r_top--;
			t=t->pre;
		}
		int temp=0;
		while(t!=NULL&&t->val<l_top+k)
		{
			a[t->val]--;
			node* t1=((t->nxt==NULL)?t->pre:t->nxt);
			l.remove(t);
			t=t1;
			temp++;
		}
		if(l.size()<=0)
		{
			return true;
		}
		if(l.size()<r_top)
		{
			r_top=l.size();
		}
		if(t==NULL&&r_top>0)
		{
			t=l.sit(r_top);
		}
		node *temp1=t;
		for(int i=1;i<=k&&temp1!=NULL;i++)
		{
			while(temp1!=NULL&&temp1->val<l_top+k)
			{
				a[temp1->val]--;
				node* temp2=temp1->nxt;
				l.remove(temp1);
				temp1=temp2;
				temp++;
			}
			if(temp1!=NULL)
			{
				temp1=temp1->nxt;
			}
			else
			{
				break;	
			}
			
		}
		if(temp==0&&l.size()-r_top+1<=k)
		{
			return false;
		}
		if(temp==0)
		{
			r_top++;
			t=t->nxt;
		}
	}
	return true;
}
int main()
{
	int t;
	scanf("%d",&t);
	while(t--)
	{

		printf("%s\n",(f()?"YES":"NO"));
	}
	return 0;
}
